#include<bits/stdc++.h>
using namespace std;
struct node
{
    long long x,y,z,id;
    bool f;
    bool operator<(const node&b)const
    {
        return x<b.x;
    }
}a[600010],b[600010],c[600010];
int read()
{
    int x=0;
    char ch=getchar();
    while(!isdigit(ch))
    {
        ch=getchar();
    }
    while(isdigit(ch))
    {
        x=x*10+(ch-'0');
        ch=getchar();
    }
    return x;
}
long long lowbit(long long x)
{
    return x&-x;
}
long long sum[6000010];
long long ans[600010],n,m,maxx,maxy,tot;
void update(long long x,long long v)
{
    for(long long i=x;i<=maxy;i+=lowbit(i))
    {
        sum[i]=max(sum[i],v);
    }
}
void clear(long long x)
{
    for(long long i=x;i<=maxy;i+=lowbit(i))
    {
        if(!sum[i])
        {
            return;
        }
        sum[i]=0;
    }
}
long long query(long long x)
{
    long long ans=0;
    for(long long i=x;i>=1;i-=lowbit(i))
    {
        ans=max(ans,sum[i]);
    }
    return ans;
}
void cdq(long long l,long long r)
{
    if(l>=r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    cdq(l,mid);
    cdq(mid+1,r);
    long long i=l,j=mid+1;
    while(j<=r)
    {
        if(!a[j].f)
        {
            while(i<=mid&&a[i].x<=a[j].x)
            {
                if(a[i].f)
                {
                    update(a[i].y,a[i].x+a[i].y);
                }
                i++;
            }
            long long tmp=query(a[j].y);
            if(tmp)
            {
                ans[a[j].id]=min(ans[a[j].id],a[j].x+a[j].y-tmp);
            }
        }
        j++;
    }
    for(long long k=l;k<i;k++)
    {
        if(a[k].f)
        {
            clear(a[k].y);
        }
    }
    merge(a+l,a+mid+1,a+mid+1,a+r+1,b+l);
    for(long long i=l;i<=r;i++)
    {
        a[i]=b[i];
    }
}
void del()
{
    long long rx=0,ry=0;
    m=0;
    for(long long i=1;i<=n;i++)
    {
        if(!a[i].f)
        {
            rx=max(rx,a[i].x);
            ry=max(ry,a[i].y);
        }
    }
    for(long long i=1;i<=n;i++)
    {
        if(a[i].x<=rx&&a[i].y<=ry)
        {
            b[++m]=a[i];
        }
    }
    for(long long i=1;i<=m;i++)
    {
        a[i]=b[i];
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        a[i].x=read(),a[i].y=read();
        a[i].x++;
        a[i].y++;
        a[i].f=true;
        a[i].id=i;
        maxx=max(maxx,a[i].x);
        maxy=max(maxy,a[i].y);
    }
    while(m--)
    {
        long long k=read(),x=read(),y=read();
        x++;
        y++;
        n++;
        a[n].x=x;
        a[n].y=y;
        a[n].id=n;
        a[n].f=(k==1);
        maxx=max(maxx,x);
        maxy=max(maxy,y);
    }
    for(long long i=1;i<=n;i++)
    {
        ans[i]=1e9;
        c[i]=a[i];
    }
    maxx++;
    maxy++;
    del();
    cdq(1,m);
    for(long long i=1;i<=n;i++)
    {
        a[i]=c[i];
        a[i].x=maxx-a[i].x;
    }
    del();
    cdq(1,m);
    for(long long i=1;i<=n;i++)
    {
        a[i]=c[i];
        a[i].y=maxy-a[i].y;
    }
    del();
    cdq(1,m);
    for(long long i=1;i<=n;i++)
    {
        a[i]=c[i];
        a[i].x=maxx-a[i].x;
        a[i].y=maxy-a[i].y;
    }
    del();
    cdq(1,m);
    for(long long i=1;i<=n;i++)
    {
        if(!c[i].f)
        {
            printf("%lld\n",ans[c[i].id]);
        }
    }
    return 0;
}
